use std::{env, fs, path::PathBuf};

fn main() {
    let manifest_dir =
        PathBuf::from(env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR is set"));
    let linker_dir = manifest_dir.join("linker");
    let selftest = env::var("KERNEL_SELFTEST").unwrap_or_default();
    let user_smoke = env::var("KERNEL_USER_SMOKE").unwrap_or_default();
    let test_filter = env::var("KERNEL_TEST_FILTER").unwrap_or_default();
    let test_suite = match env::var("KERNEL_TEST_SUITE").as_deref() {
        Ok("submit") => "submit".to_string(),
        Ok("basic") => "basic".to_string(),
        Ok("busybox") => "busybox".to_string(),
        Ok("libctest") => "libctest".to_string(),
        Ok("lua") => "lua".to_string(),
        Ok("libcbench") => "libcbench".to_string(),
        Ok("lmbench") => "lmbench".to_string(),
        Ok("unixbench") => "unixbench".to_string(),
        Ok("iozone") => "iozone".to_string(),
        Ok("cyclictest") => "cyclictest".to_string(),
        Ok("ltp") => "ltp".to_string(),
        Ok("iperf") => "iperf".to_string(),
        Ok("netperf") => "netperf".to_string(),
        _ => "submit".to_string(),
    };
    let trace_syscall = env::var("KERNEL_TRACE_SYSCALL").unwrap_or_default();
    let trace_thread = env::var("KERNEL_TRACE_THREAD").unwrap_or_default();
    let submit_start = env::var("KERNEL_SUBMIT_START").unwrap_or_default();
    let submit_stop_after = env::var("KERNEL_SUBMIT_STOP_AFTER").unwrap_or_default();
    let test_variant = env::var("KERNEL_TEST_VARIANT").unwrap_or_else(|_| "all".to_string());
    let user_smoke_elf = env::var("KERNEL_USER_SMOKE_ELF").unwrap_or_else(|_| {
        let path = PathBuf::from(env::var("OUT_DIR").expect("OUT_DIR is set"))
            .join("empty-user-smoke.elf");
        fs::write(&path, []).expect("write empty user smoke placeholder");
        path.display().to_string()
    });

    let target_arch = env::var("CARGO_CFG_TARGET_ARCH").expect("target arch is set");
    let feature_riscv = env::var_os("CARGO_FEATURE_ARCH_RISCV64").is_some();
    let feature_loongarch = env::var_os("CARGO_FEATURE_ARCH_LOONGARCH64").is_some();

    if feature_riscv == feature_loongarch {
        panic!("enable exactly one architecture feature: arch-riscv64 or arch-loongarch64");
    }

    let script = match (target_arch.as_str(), feature_riscv, feature_loongarch) {
        ("riscv64", true, false) => "riscv64-qemu.ld",
        ("loongarch64", false, true) => "loongarch64-qemu.ld",
        ("riscv64", false, true) => panic!("arch-loongarch64 cannot be used with riscv64 target"),
        ("loongarch64", true, false) => {
            panic!("arch-riscv64 cannot be used with loongarch64 target")
        }
        _ => panic!("unsupported target architecture: {target_arch}"),
    };

    println!(
        "cargo:rustc-link-arg=-T{}",
        linker_dir.join(script).display()
    );
    println!(
        "cargo:rerun-if-changed={}",
        linker_dir.join(script).display()
    );
    println!("cargo:rerun-if-env-changed=KERNEL_SELFTEST");
    println!("cargo:rustc-env=KERNEL_SELFTEST={selftest}");
    println!("cargo:rerun-if-env-changed=KERNEL_TEST_FILTER");
    println!("cargo:rustc-env=KERNEL_TEST_FILTER={test_filter}");
    println!("cargo:rerun-if-env-changed=KERNEL_TEST_SUITE");
    println!("cargo:rustc-env=KERNEL_TEST_SUITE={test_suite}");
    println!("cargo:rerun-if-env-changed=KERNEL_TRACE_SYSCALL");
    println!("cargo:rustc-env=KERNEL_TRACE_SYSCALL={trace_syscall}");
    println!("cargo:rerun-if-env-changed=KERNEL_TRACE_THREAD");
    println!("cargo:rustc-env=KERNEL_TRACE_THREAD={trace_thread}");
    println!("cargo:rerun-if-env-changed=KERNEL_SUBMIT_START");
    println!("cargo:rustc-env=KERNEL_SUBMIT_START={submit_start}");
    println!("cargo:rerun-if-env-changed=KERNEL_SUBMIT_STOP_AFTER");
    println!("cargo:rustc-env=KERNEL_SUBMIT_STOP_AFTER={submit_stop_after}");
    println!("cargo:rerun-if-env-changed=KERNEL_TEST_VARIANT");
    println!("cargo:rustc-env=KERNEL_TEST_VARIANT={test_variant}");
    println!("cargo:rerun-if-env-changed=KERNEL_USER_SMOKE_ELF");
    println!("cargo:rerun-if-env-changed=KERNEL_USER_SMOKE");
    println!("cargo:rerun-if-changed={user_smoke_elf}");
    println!("cargo:rustc-env=KERNEL_USER_SMOKE_ELF={user_smoke_elf}");
    println!("cargo:rustc-env=KERNEL_USER_SMOKE={user_smoke}");
}

