pub struct SpinLock<T> {
    locked: AtomicBool,
    value: UnsafeCell<T>,
}

// SAFETY: SpinLock<T> is safe to Send when T is Send because
// the lock ensures mutual exclusion — only one thread can access
// the inner value at a time through the lock guard.
unsafe impl<T: Send> Send for SpinLock<T> {}
// SAFETY: SpinLock<T> is safe to Sync when T is Send because
// only one thread can hold a mutable reference (through the guard)
// while other threads must acquire the lock first.
unsafe impl<T: Send> Sync for SpinLock<T> {}

impl<T> SpinLock<T> {
    pub const fn new(value: T) -> Self {
        Self {
            locked: AtomicBool::new(false),
            value: UnsafeCell::new(value),
        }
    }

    pub fn lock(&self) -> SpinLockGuard<'_, T> {
        while self
            .locked
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            while self.locked.load(Ordering::Relaxed) {
                spin_loop();
