const VERSION: &str = env!("CARGO_PKG_VERSION");

pub fn banner(hart_id: usize, dtb_pa: usize) {
    crate::println!(
        "OSKernel2026 kernel v{} booted on hart {} dtb=0x{:016x}",
        VERSION,
        hart_id,
        dtb_pa
    );
}

pub fn shutdown_requested() {
    crate::println!("shutdown requested");
}

pub fn panic(info: &PanicInfo<'_>) {
    crate::println!("kernel panic");
    if let Some(location) = info.location() {
        print_module(location.file());
        crate::println!("  at {}:{}", location.file(), location.line());
    } else {
        crate::println!("  module: <unknown>");
        crate::println!("  at <unknown>");
    }

    crate::println!("  message: {}", info.message());

    let ctx = crate::arch::panic_context();
    crate::println!("  hart: {}", ctx.hart_id);
    print_optional("scause", ctx.scause);
    print_optional("sepc", ctx.sepc);
    print_optional("stval", ctx.stval);
}

fn print_module(file: &str) {
    match module_path(file) {
        Some(module) => {
            crate::print!("  module: ");
            print_module_segments(module);
            crate::println!();
        }
        None => crate::println!("  module: <unknown>"),
    }
}

fn module_path(file: &str) -> Option<&str> {
    let src = strip_prefix_until(file, "kernel/src/")?;
    let without_suffix = strip_suffix(src, ".rs")?;
    Some(strip_suffix(without_suffix, "/mod").unwrap_or(without_suffix))
}

fn strip_prefix_until<'a>(value: &'a str, prefix: &str) -> Option<&'a str> {
    let bytes = value.as_bytes();
    let prefix_bytes = prefix.as_bytes();
    if prefix_bytes.is_empty() || bytes.len() < prefix_bytes.len() {
        return None;
    }

    let last_start = bytes.len() - prefix_bytes.len();
    let mut start = 0;
    while start <= last_start {
        let mut offset = 0;
        while offset < prefix_bytes.len() && bytes[start + offset] == prefix_bytes[offset] {
            offset += 1;
        }
        if offset == prefix_bytes.len() {
            return Some(&value[start + prefix_bytes.len()..]);
        }
        start += 1;
    }
    None
}

fn strip_suffix<'a>(value: &'a str, suffix: &str) -> Option<&'a str> {
    if value.as_bytes().ends_with(suffix.as_bytes()) {
        Some(&value[..value.len() - suffix.len()])
    } else {
        None
    }
}

fn print_module_segments(module: &str) {
    for byte in module.bytes() {
        if byte == b'/' {
            crate::print!("::");
        } else {
            crate::print!("{}", byte as char);
        }
    }
}

fn print_optional(name: &str, value: Option<usize>) {
    match value {
        Some(value) => crate::println!("  {}: 0x{:016x}", name, value),
        None => crate::println!("  {}: <unavailable>", name),
    }
}

